const lookbackDays = items[0].json.lookback_days || 14;
const lookbackDate = new Date();
lookbackDate.setDate(lookbackDate.getDate() - parseInt(lookbackDays));

return {
  lookback_days: parseInt(lookbackDays),
  lookback_iso: lookbackDate.toISOString(),
  query_ts: new Date().toISOString()
};

const metrics = items;

if (metrics.length === 0) {
  return {
    status: 'cold_start',
    message: 'No metrics available yet (system warm-up phase)',
    metrics_count: 0,
    uses_defaults: true
  };
}

const aggregated = {
  metrics_count: metrics.length,
  total_engagement: 0,
  platforms: {},
  languages: {},
  period_hours: metrics.length > 0 ? Math.round((Date.now() - new Date(metrics[metrics.length - 1].measured_at)) / 3600000) : 0
};

metrics.forEach(m => {
  const engagement = (m.likes || 0) + (m.comments || 0) * 2 + (m.shares || 0) * 3;
  aggregated.total_engagement += engagement;

  if (!aggregated.platforms[m.platform]) {
    aggregated.platforms[m.platform] = {
      count: 0,
      avg_engagement: 0,
      total_engagement: 0
    };
  }
  aggregated.platforms[m.platform].count++;
  aggregated.platforms[m.platform].total_engagement += engagement;

  if (m.lang) {
    if (!aggregated.languages[m.lang]) {
      aggregated.languages[m.lang] = { count: 0, total_engagement: 0 };
    }
    aggregated.languages[m.lang].count++;
    aggregated.languages[m.lang].total_engagement += engagement;
  }
});

return aggregated;

const telegramToken = $env.TELEGRAM_BOT_TOKEN;
const chatId = $env.TELEGRAM_CHAT_ID_ADMIN;
const timestamp = new Date().toISOString().split('T')[0];

return {
  token: telegramToken,
  chat_id: chatId,
  message: `⚠️ Learning Loop W41 — ${timestamp}\n\nStatus: COLD START (no metrics)\nMetrics count: 0\nDefault values have been set.\nSystem will be ready after first metrics arrive.`,
  parse_mode: 'HTML'
};

const metrics = $node["load_metrics_window"].json;

if (!metrics || metrics.length === 0) {
  return [];
}

const topicScores = {};

metrics.forEach(m => {
  const topic = m.topic_tag || 'untagged';
  const engagement = (m.likes || 0) + (m.comments || 0) * 2 + (m.shares || 0) * 3;
  const engagementRate = m.engagement_rate || 0;

  if (!topicScores[topic]) {
    topicScores[topic] = {
      topic: topic,
      count: 0,
      total_engagement: 0,
      total_impressions: m.views || 0,
      weighted_engagement_rate: 0,
      posts: []
    };
  }

  topicScores[topic].count++;
  topicScores[topic].total_engagement += engagement;
  topicScores[topic].total_impressions += (m.views || 0);
  topicScores[topic].posts.push({
    id: m.social_published_id,
    published_at: m.published_at,
    engagement_rate: engagementRate
  });
});

// Calcola weighted engagement rate
Object.keys(topicScores).forEach(t => {
  const topic = topicScores[t];
  if (topic.total_impressions > 0) {
    topic.weighted_engagement_rate = (topic.total_engagement / topic.total_impressions * 100).toFixed(2);
  }
  // Trend: slope ultimi 7gg vs prima
  const now = Date.now();
  const sevenDaysAgo = now - 7 * 24 * 60 * 60 * 1000;
  const recentPosts = topic.posts.filter(p => new Date(p.published_at) > sevenDaysAgo).length;
  topic.trend_recent_days = recentPosts;
  delete topic.posts; // remove per output
});

return Object.values(topicScores).sort((a, b) => b.total_engagement - a.total_engagement);

const metrics = $node["load_metrics_window"].json;

if (!metrics || metrics.length === 0) {
  return [];
}

const hashtagScores = {};

metrics.forEach(m => {
  if (!m.hashtags) return;

  const hashtags = typeof m.hashtags === 'string' ? m.hashtags.split(',').map(h => h.trim()) : m.hashtags;
  const engagement = (m.likes || 0) + (m.comments || 0) * 2 + (m.shares || 0) * 3;

  hashtags.forEach(tag => {
    if (!hashtagScores[tag]) {
      hashtagScores[tag] = {
        hashtag: tag,
        count: 0,
        total_engagement: 0,
        avg_engagement: 0
      };
    }
    hashtagScores[tag].count++;
    hashtagScores[tag].total_engagement += engagement;
  });
});

Object.keys(hashtagScores).forEach(tag => {
  hashtagScores[tag].avg_engagement = (hashtagScores[tag].total_engagement / hashtagScores[tag].count).toFixed(2);
});

return Object.values(hashtagScores)
  .sort((a, b) => b.total_engagement - a.total_engagement)
  .slice(0, 30); // Top 30

const metrics = $node["load_metrics_window"].json;

if (!metrics || metrics.length === 0) {
  return {
    instagram: { weekday: ['18:00', '19:00', '20:00'], weekend: ['15:00', '16:00', '17:00'] },
    tiktok: { weekday: ['19:00', '20:00', '21:00'], weekend: ['14:00', '15:00', '16:00'] },
    facebook: { weekday: ['17:00', '18:00', '19:00'], weekend: ['12:00', '13:00', '14:00'] }
  };
}

const timings = {};

metrics.forEach(m => {
  const platform = m.platform || 'unknown';
  if (!m.published_at) return;

  const pubDate = new Date(m.published_at);
  const hour = String(pubDate.getUTCHours()).padStart(2, '0');
  const dow = pubDate.getUTCDay();
  const isDayType = (dow === 0 || dow === 6) ? 'weekend' : 'weekday';
  const timeKey = `${hour}:00`;

  if (!timings[platform]) {
    timings[platform] = { weekday: {}, weekend: {} };
  }

  const engagement = (m.likes || 0) + (m.comments || 0) * 2 + (m.shares || 0) * 3;

  if (!timings[platform][isDayType][timeKey]) {
    timings[platform][isDayType][timeKey] = { count: 0, total_engagement: 0 };
  }
  timings[platform][isDayType][timeKey].count++;
  timings[platform][isDayType][timeKey].total_engagement += engagement;
});

// Convert to top 3 times per platform/day type
const result = {};
Object.keys(timings).forEach(platform => {
  result[platform] = {};
  ['weekday', 'weekend'].forEach(dayType => {
    const times = Object.entries(timings[platform][dayType])
      .sort((a, b) => b[1].total_engagement - a[1].total_engagement)
      .slice(0, 3)
      .map(([time]) => time);
    result[platform][dayType] = times.length > 0 ? times : ['12:00', '18:00'];
  });
});

return result;

const metrics = $node["load_metrics_window"].json;

if (!metrics || metrics.length === 0) {
  return [];
}

const formatScores = {};

metrics.forEach(m => {
  const format = m.asset_type || 'video';
  const engagement = (m.likes || 0) + (m.comments || 0) * 2 + (m.shares || 0) * 3;

  if (!formatScores[format]) {
    formatScores[format] = {
      format: format,
      count: 0,
      total_engagement: 0,
      avg_engagement: 0
    };
  }
  formatScores[format].count++;
  formatScores[format].total_engagement += engagement;
});

Object.keys(formatScores).forEach(f => {
  formatScores[f].avg_engagement = (formatScores[f].total_engagement / formatScores[f].count).toFixed(2);
});

return Object.values(formatScores).sort((a, b) => b.avg_engagement - a.avg_engagement);

const metrics = $node["load_metrics_window"].json;

if (!metrics || metrics.length === 0) {
  return [];
}

const langScores = {};

metrics.forEach(m => {
  const lang = m.lang || 'unknown';
  const engagement = (m.likes || 0) + (m.comments || 0) * 2 + (m.shares || 0) * 3;
  const views = m.views || 1;

  if (!langScores[lang]) {
    langScores[lang] = {
      lang: lang,
      count: 0,
      total_engagement: 0,
      total_views: 0,
      engagement_rate: 0
    };
  }
  langScores[lang].count++;
  langScores[lang].total_engagement += engagement;
  langScores[lang].total_views += views;
});

Object.keys(langScores).forEach(lang => {
  const score = langScores[lang];
  score.engagement_rate = (score.total_engagement / score.total_views * 100).toFixed(2);
});

return Object.values(langScores).sort((a, b) => b.engagement_rate - a.engagement_rate);

const topicScores = $node["compute_topic_scores"].json;
const hashtagPerf = $node["compute_hashtag_perf"].json;
const bestTimes = $node["compute_best_times"].json;
const langPerf = $node["compute_lang_perf"].json;
const metricsCount = $node["validate_metrics"].json.metrics_count;

const topTopic = topicScores.length > 0 ? topicScores[0].topic : 'N/A';
const topHashtag = hashtagPerf.length > 0 ? hashtagPerf[0].hashtag : 'N/A';
const topLang = langPerf.length > 0 ? langPerf[0].lang : 'N/A';
const topLangEngagement = langPerf.length > 0 ? langPerf[0].engagement_rate : 'N/A';
const dateStr = new Date().toISOString().split('T')[0];

const telegramToken = $env.TELEGRAM_BOT_TOKEN;
const chatId = $env.TELEGRAM_CHAT_ID_ADMIN;

const message = `
✅ <b>Learning Loop W41 — ${dateStr}</b>\n\n
📊 <b>Analytics Summary</b>\n
Metrics analyzed: <b>${metricsCount}</b>\n
Top Topic: <b>#${topTopic}</b>\nTop Hashtag: <b>${topHashtag}</b>\nTop Language: <b>${topLang}</b> (+${topLangEngagement}% engagement)\n\n
🎯 <b>Config Updated</b>\n
✓ topic_scores\n✓ top_hashtags (top 30)\n✓ best_post_times (by platform/weekday)\n✓ winning_formats\n✓ lang_performance\n✓ last_learning_run_at\n\n
🗂️ <b>Performance Insights Stored</b>\n
Topic records: ${topicScores.length}\nHashtag records: ${hashtagPerf.length}\nLanguage records: ${langPerf.length}\n\n
⏰ <b>Next Cycle Ready</b>\nReady for W00 Master Orchestrator + content generation.`;

return {
  token: telegramToken,
  chat_id: chatId,
  message: message,
  parse_mode: 'HTML',
  metrics_count: metricsCount,
  insights_generated: {
    topics: topicScores.length,
    hashtags: hashtagPerf.length,
    languages: langPerf.length
  }
};
